options.dotDiagram:
digraph PluginArchitecture {
  node [style=filled, fontcolor=white, fontname="Helvetica"];

  // Input Layer
  UserInput [label="<header> 👤 User Input|<builder> Builder|<code> Code|<query> Query", shape=record];

  // Core Processing Cluster
  subgraph cluster_processing {
    label=<<FONT POINT-SIZE="12"><I>Graphviz Processing</I></FONT>>;
    style="rounded,dashed";
    color="#6a787a";
    fontcolor="#6a787a";

    DOTParser [label="DOT Parser\n🔍", shape=box];
    Validator [label="DOT\nValidator\n✅", shape=diamond];

    LayoutEngines [label="<header> 🎯 Layout Engines|<dot> Hierarchical|<neato> Network|<fdp> Force Directed|<circo> Circular", shape=record];
  }



  // Rendering Pipeline Cluster
  subgraph cluster_rendering {
    label=<<FONT POINT-SIZE="12"><I>Panel Rendering Pipeline</I></FONT>>;
    style="rounded,dashed";
    color="#6a787a";
    fontcolor="#6a787a";

    SVGRenderer [label="SVG Renderer\n🎨", shape=box];
    ThemeSystem [label="Theme System\n🌓", shape=box];
    HoverSystem [label="Hover & Click\nHandlers 🖱️", shape=box];
    PositionCalc [label="Position\nCalculator\n📐", shape=box];

    // Define order within cluster
    SVGRenderer -> ThemeSystem -> HoverSystem -> PositionCalc [style=invis];
  }

  // Data Integration Cluster
  subgraph cluster_data {
    label=<<FONT POINT-SIZE="12"><I>Grafana Data Integration</I></FONT>>;
    style="rounded,dashed";
    color="#6a787a";
    fontcolor="#6a787a";

    GrafanaDatasource [label="Grafana\nDatasource(s)\n📊📈", shape=cylinder];

    DataBindings [label="<header> 🔗 Live Data Bindings|<colors> Color Overrides|<labels> Label Interpolation|<tooltips> Tooltips & Datalinks", shape=record];
  }

  // Output
  FinalViz [label="Interactive\nGraphviz\nDiagram\n🪄✨", shape=box, penwidth=3, style="filled,rounded", margin="0.5"];

  // Flow - Rainbow gradient using solarized accent colors
  UserInput -> DOTParser [color="#db7093", penwidth=2.5];

  DOTParser -> Validator [color="#6c71c4", penwidth=2.5];
  Validator -> DOTParser [color="#6c71c4", penwidth=2.5];
  DOTParser -> LayoutEngines [color="#268bd2", penwidth=2.5];
  Validator -> LayoutEngines [color="#268bd2", penwidth=2, style=dotted];

  LayoutEngines:dot -> SVGRenderer:w [color="#2aa198", penwidth=2];
  LayoutEngines:neato -> SVGRenderer:w [color="#2aa198", penwidth=2];
  LayoutEngines:fdp -> SVGRenderer:w [color="#2aa198", penwidth=2];
  LayoutEngines:circo -> SVGRenderer:w [color="#2aa198", penwidth=2];

  SVGRenderer -> ThemeSystem [color="#32cd32", penwidth=2.5];
  SVGRenderer -> PositionCalc [color="#ff8c00", penwidth=2.5];
  SVGRenderer -> HoverSystem [color="#daa520", penwidth=2.5];
  PositionCalc -> HoverSystem [color="#ff8c00", penwidth=2.5];

  ThemeSystem -> FinalViz [color="#ff4500", penwidth=2.5];
  PositionCalc -> FinalViz [color="#dc143c", penwidth=2.5];

  GrafanaDatasource -> DataBindings:header:w [color="#2aa198", penwidth=2.5, style=dotted];

  DataBindings:colors -> ThemeSystem [color="#9acd32", penwidth=2, style=dotted];
  DataBindings:labels -> FinalViz [color="#ff6347", penwidth=2, style=dotted];
  DataBindings:tooltips -> HoverSystem [color="#ffa500", penwidth=2, style=dotted];

  FinalViz -> HoverSystem [color="#ff1493", penwidth=2.5];
  HoverSystem -> FinalViz [color="#ff00ff", penwidth=2.5];
}
